mapper.insert:
insert into login_record (
  id, employeeNumber, employeeName, loginStatus, ipAddress, userAgent, loginTime
) values (
  #{id}, #{employeeNumber}, #{employeeName}, #{loginStatus}, #{ipAddress}, #{userAgent}, #{loginTime}
)

mapper.select:
select id, employeeNumber, employeeName, loginStatus, ipAddress, userAgent, loginTime
from login_record
where employeeNumber = #{employeeNumber}
order by loginTime desc
limit #{limitSize}
